export interface Gateway {
  charge(customerId: string, cents: number): Promise<{ confirmation: string }>;
}

export async function chargeCustomer(
  gw: Gateway,
  customerId: string,
  cents: number,
): Promise<string | null> {
  try {
    const result = await gw.charge(customerId, cents);
    return result.confirmation;
  } catch (ex) {
    return null;
  }
}
